import type { MTGA } from "../index.js";
import { MTGAModule } from "../types/module.js";
import type { IPairs } from "../types/pair.js";
import { isComposingKeyboardEvent, parseKeyboardEvent } from "../utils/event.js";
import { getClosing, getOpening, isClosing, isOpening, isPair } from "../utils/pair.js";

const overtypeClosingHandler = function (this: AutoPairModule, e: KeyboardEvent) {
  if (e.defaultPrevented) {
    return;
  }

  if (isComposingKeyboardEvent(e)) {
    return;
  }

  const mtga = this.parent;
  const el = this.parent.element;
  const pairs = this.pairs;

  const { key, altKey, ctrlKey } = parseKeyboardEvent(e);
  const isValid = !ctrlKey && !altKey && isClosing(pairs, key);
  if (!isValid) {
    return;
  }

  const { short, long, dir, isReversed } = mtga.getState();
  if (short !== long) {
    return;
  }

  const currChar = el.value.charAt(short);
  if (currChar !== key) {
    return;
  }

  if (!getOpening(pairs, key)) {
    return;
  }

  e.preventDefault();

  mtga.setState({
    isReversed,
    short: short + 1,
    long: long + 1,
    dir,
  });
};

const closePairHandler = function (this: AutoPairModule, e: KeyboardEvent) {
  if (e.defaultPrevented) {
    return;
  }

  if (isComposingKeyboardEvent(e)) {
    return;
  }

  const mtga = this.parent;
  const el = this.parent.element;
  const pairs = this.pairs;

  const { key, altKey, ctrlKey, shiftKey } = parseKeyboardEvent(e);

  const isValid = !ctrlKey && !altKey && isOpening(pairs, key);
  if (!isValid) {
    return;
  }

  e.preventDefault();

  const { short, long, dir, isReversed } = mtga.getState();

  const isRange = short !== long;
  const opening = key;
  const closing = getClosing(pairs, opening);

  const left = el.value.substring(0, short);
  const center = el.value.substring(short, long);
  const right = el.value.substring(long);

  let newShort: number, newLong: number, newValue: string;

  if (!isRange) {
    const start = (left + opening).length;
    newValue = left + opening + closing + right;
    newShort = start;
    newLong = start;
  } else {
    newValue = left + opening + center + closing + right;
    newShort = (left + opening).length;
    newLong = (left + opening + center).length;
  }

  mtga.setState({
    isReversed,
    short: newShort,
    long: newLong,
    dir,
    value: newValue,
  });
};

const clearPairHandler = function (this: AutoPairModule, e: KeyboardEvent) {
  if (e.defaultPrevented) {
    return;
  }

  if (isComposingKeyboardEvent(e)) {
    return;
  }

  const mtga = this.parent;
  const el = this.parent.element;
  const pairs = this.pairs;

  const { key, altKey, ctrlKey, shiftKey } = parseKeyboardEvent(e);

  const isRemoveKey = !ctrlKey && !altKey && key === "Backspace";
  if (!isRemoveKey) {
    return;
  }

  const { short, long } = mtga.getState();

  const isRange = short !== long;
  if (isRange) {
    return;
  }

  const prevChar = el.value.charAt(short - 1);
  const currChar = el.value.charAt(short);

  if (!isPair(pairs, prevChar, currChar)) {
    return;
  }

  e.preventDefault();

  const left = el.value.substring(0, short - 1);
  const right = el.value.substring(short + 1);

  const newValue = left + right;
  const newShort = left.length;
  const newLong = left.length;

  mtga.setState({
    isReversed: false,
    short: newShort,
    long: newLong,
    dir: "forward",
    value: newValue,
  });
};

const onKeydown = function (this: AutoPairModule, e: KeyboardEvent): void {
  overtypeClosingHandler.call(this, e);
  closePairHandler.call(this, e);
  clearPairHandler.call(this, e);
};

export class AutoPairModule extends MTGAModule {
  pairs: IPairs;

  constructor(parent: MTGA) {
    super(parent, AutoPairModule.name);
    this.pairs = { ...AutoPairModule.defaults.pairs };
  }

  static name = "AutoPair";

  static defaults: {
    pairs: IPairs;
  } = {
    pairs: {
      "(": ")",
      "[": "]",
      "{": "}",
      "<": ">",
      "'": "'",
      '"': '"',
      "`": "`",
    },
  };

  onKeydown: typeof onKeydown = onKeydown;
}
